SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>2800000000.0) AND (t.Risk_Rating <= 4) AND (t.PCF>2.0) AND (t.PCF < 16.0) AND (t.NP_P0 > 0) AND (t.NP_P0/ NULLIF(t.NP_P1, 0)>1.14) AND (t.PE>0.0) AND (t.PE < 14.0) AND ((t.CF_OA_5Y/ NULLIF(t.OShares, 0))> 7000.0) ORDER BY t.ticker, t.time